def generate_reference_answer():
    import json
    from mcp_client import call_tool

    execution_log = []

    # ─── Step 1: Fetch quotes for AAPL and MSFT ───────────────────────────────
    execution_log.append('Step 1a: Calling twelvedata_GetQuote for AAPL')
    raw_aapl_quote = call_tool('twelvedata_GetQuote', {'params': {'symbol': 'AAPL', 'interval': '1day'}})
    execution_log.append(f'[RAW AAPL quote] {str(raw_aapl_quote)[:300]}')
    aapl_quote = json.loads(raw_aapl_quote) if isinstance(raw_aapl_quote, str) else raw_aapl_quote

    execution_log.append('Step 1b: Calling twelvedata_GetQuote for MSFT')
    raw_msft_quote = call_tool('twelvedata_GetQuote', {'params': {'symbol': 'MSFT', 'interval': '1day'}})
    execution_log.append(f'[RAW MSFT quote] {str(raw_msft_quote)[:300]}')
    msft_quote = json.loads(raw_msft_quote) if isinstance(raw_msft_quote, str) else raw_msft_quote

    # Extract key fields defensively
    aapl_close = aapl_quote.get('close', 'N/A')
    aapl_pct_str = aapl_quote.get('percent_change', '0')
    msft_close = msft_quote.get('close', 'N/A')
    msft_pct_str = msft_quote.get('percent_change', '0')

    try:
        aapl_pct = float(aapl_pct_str) if aapl_pct_str is not None else 0.0
    except (TypeError, ValueError):
        aapl_pct = 0.0
    try:
        msft_pct = float(msft_pct_str) if msft_pct_str is not None else 0.0
    except (TypeError, ValueError):
        msft_pct = 0.0

    execution_log.append(f'AAPL close={aapl_close}, percent_change={aapl_pct}')
    execution_log.append(f'MSFT close={msft_close}, percent_change={msft_pct}')

    # ─── Step 2: Branch logic for AAPL ───────────────────────────────────────
    aapl_branch = None
    aapl_indicator = {}

    if abs(aapl_pct) >= 1.5:
        aapl_branch = 'A'
        execution_log.append(f'AAPL Branch A triggered (abs({aapl_pct}) >= 1.5): fetching RSI')
        raw_aapl_rsi = call_tool('twelvedata_GetTimeSeriesRsi', {
            'params': {
                'symbol': 'AAPL',
                'interval': '1day',
                'time_period': 14,
                'outputsize': 5
            }
        })
        execution_log.append(f'[RAW AAPL RSI] {str(raw_aapl_rsi)[:300]}')
        aapl_rsi_data = json.loads(raw_aapl_rsi) if isinstance(raw_aapl_rsi, str) else raw_aapl_rsi
        aapl_values = aapl_rsi_data.get('values', [])
        if aapl_values:
            latest_rsi = aapl_values[0].get('rsi', 'N/A')
        else:
            latest_rsi = 'N/A'
        aapl_indicator = {'rsi': latest_rsi}
        execution_log.append(f'AAPL latest RSI (14-period, 1day): {latest_rsi}')
    else:
        aapl_branch = 'B'
        execution_log.append(f'AAPL Branch B triggered (abs({aapl_pct}) < 1.5): fetching Bollinger Bands')
        raw_aapl_bb = call_tool('twelvedata_GetTimeSeriesBBands', {
            'params': {
                'symbol': 'AAPL',
                'interval': '1day',
                'time_period': 20,
                'outputsize': 3
            }
        })
        execution_log.append(f'[RAW AAPL BBands] {str(raw_aapl_bb)[:300]}')
        aapl_bb_data = json.loads(raw_aapl_bb) if isinstance(raw_aapl_bb, str) else raw_aapl_bb
        aapl_bb_values = aapl_bb_data.get('values', [])
        if aapl_bb_values:
            latest_upper = aapl_bb_values[0].get('upper_band', 'N/A')
            latest_lower = aapl_bb_values[0].get('lower_band', 'N/A')
        else:
            latest_upper = 'N/A'
            latest_lower = 'N/A'
        aapl_indicator = {'upper_band': latest_upper, 'lower_band': latest_lower}
        execution_log.append(f'AAPL latest BBands (20-period, 1day): upper={latest_upper}, lower={latest_lower}')

    # ─── Step 3: Branch logic for MSFT ───────────────────────────────────────
    msft_branch = None
    msft_indicator = {}

    if abs(msft_pct) >= 1.5:
        msft_branch = 'A'
        execution_log.append(f'MSFT Branch A triggered (abs({msft_pct}) >= 1.5): fetching RSI')
        raw_msft_rsi = call_tool('twelvedata_GetTimeSeriesRsi', {
            'params': {
                'symbol': 'MSFT',
                'interval': '1day',
                'time_period': 14,
                'outputsize': 5
            }
        })
        execution_log.append(f'[RAW MSFT RSI] {str(raw_msft_rsi)[:300]}')
        msft_rsi_data = json.loads(raw_msft_rsi) if isinstance(raw_msft_rsi, str) else raw_msft_rsi
        msft_values = msft_rsi_data.get('values', [])
        if msft_values:
            latest_rsi = msft_values[0].get('rsi', 'N/A')
        else:
            latest_rsi = 'N/A'
        msft_indicator = {'rsi': latest_rsi}
        execution_log.append(f'MSFT latest RSI (14-period, 1day): {latest_rsi}')
    else:
        msft_branch = 'B'
        execution_log.append(f'MSFT Branch B triggered (abs({msft_pct}) < 1.5): fetching Bollinger Bands')
        raw_msft_bb = call_tool('twelvedata_GetTimeSeriesBBands', {
            'params': {
                'symbol': 'MSFT',
                'interval': '1day',
                'time_period': 20,
                'outputsize': 3
            }
        })
        execution_log.append(f'[RAW MSFT BBands] {str(raw_msft_bb)[:300]}')
        msft_bb_data = json.loads(raw_msft_bb) if isinstance(raw_msft_bb, str) else raw_msft_bb
        msft_bb_values = msft_bb_data.get('values', [])
        if msft_bb_values:
            latest_upper = msft_bb_values[0].get('upper_band', 'N/A')
            latest_lower = msft_bb_values[0].get('lower_band', 'N/A')
        else:
            latest_upper = 'N/A'
            latest_lower = 'N/A'
        msft_indicator = {'upper_band': latest_upper, 'lower_band': latest_lower}
        execution_log.append(f'MSFT latest BBands (20-period, 1day): upper={latest_upper}, lower={latest_lower}')

    # ─── Step 4: Ordering and final briefing ─────────────────────────────────
    stocks = [
        {'symbol': 'AAPL', 'close': aapl_close, 'pct': aapl_pct, 'branch': aapl_branch, 'indicator': aapl_indicator},
        {'symbol': 'MSFT', 'close': msft_close, 'pct': msft_pct, 'branch': msft_branch, 'indicator': msft_indicator}
    ]

    # Determine order
    aapl_has_branch_a = (aapl_branch == 'A')
    msft_has_branch_a = (msft_branch == 'A')

    if aapl_has_branch_a and not msft_has_branch_a:
        # AAPL is Branch A, MSFT is Branch B => AAPL first
        ordered = [stocks[0], stocks[1]]
        execution_log.append('Ordering: AAPL (Branch A) listed first, MSFT (Branch B) second')
    elif msft_has_branch_a and not aapl_has_branch_a:
        # MSFT is Branch A, AAPL is Branch B => MSFT first
        ordered = [stocks[1], stocks[0]]
        execution_log.append('Ordering: MSFT (Branch A) listed first, AAPL (Branch B) second')
    else:
        # Both same branch => sort by abs(pct) descending
        if abs(aapl_pct) >= abs(msft_pct):
            ordered = [stocks[0], stocks[1]]
            execution_log.append(f'Both same branch ({aapl_branch}); AAPL has larger abs pct change ({abs(aapl_pct):.4f} vs {abs(msft_pct):.4f}), listed first')
        else:
            ordered = [stocks[1], stocks[0]]
            execution_log.append(f'Both same branch ({msft_branch}); MSFT has larger abs pct change ({abs(msft_pct):.4f} vs {abs(aapl_pct):.4f}), listed first')

    briefing_lines = ['=== DAILY MARKET BRIEFING ===']
    for rank, s in enumerate(ordered, 1):
        line = (f"{rank}. {s['symbol']}: price={s['close']}, percent_change={s['pct']:.4f}%, "
                f"branch={s['branch']}")
        if s['branch'] == 'A':
            line += f", RSI(14)={s['indicator'].get('rsi', 'N/A')}"
        else:
            line += (f", BB_upper={s['indicator'].get('upper_band', 'N/A')}, "
                     f"BB_lower={s['indicator'].get('lower_band', 'N/A')}")
        briefing_lines.append(line)

    execution_log.extend(briefing_lines)
    return '\n'.join(execution_log)

def generate_reference_answer():
    import json

    from mcp_client import call_tool

    execution_log = []

    # =========================================================
    # STEP 1: Market State Gate for NASDAQ
    # =========================================================
    execution_log.append('Step 1: Calling twelvedata_GetMarketState for NASDAQ')
    raw_market = call_tool('twelvedata_GetMarketState', {'exchange': 'NASDAQ'})
    execution_log.append(f'[RAW] {str(raw_market)[:200]}')
    market_data = json.loads(raw_market) if isinstance(raw_market, str) else raw_market

    # market_data is a list of exchange objects
    nasdaq_open = False
    if isinstance(market_data, list):
        for exch in market_data:
            if isinstance(exch, dict):
                name = exch.get('name', '') or ''
                if 'NASDAQ' in name.upper() or 'XNAS' in exch.get('code', '').upper():
                    nasdaq_open = bool(exch.get('is_market_open', False))
                    break
    elif isinstance(market_data, dict):
        nasdaq_open = bool(market_data.get('is_market_open', False))
    execution_log.append(f'NASDAQ is_market_open: {nasdaq_open}')

    nvda_signal = None
    nvda_branch = None

    if nasdaq_open:
        nvda_branch = 'MARKET-OPEN'
        execution_log.append('Branch MARKET-OPEN triggered')

        # Get real-time quote for NVDA
        execution_log.append('Step 1a: Calling twelvedata_GetQuote for NVDA')
        raw_quote = call_tool('twelvedata_GetQuote', {'symbol': 'NVDA', 'interval': '1day'})
        execution_log.append(f'[RAW] {str(raw_quote)[:200]}')
        quote_data = json.loads(raw_quote) if isinstance(raw_quote, str) else raw_quote
        if isinstance(quote_data, dict):
            pct_change_str = quote_data.get('percent_change', '0') or '0'
        else:
            pct_change_str = '0'
        try:
            pct_change = float(pct_change_str)
        except (ValueError, TypeError):
            pct_change = 0.0
        execution_log.append(f'NVDA percent_change: {pct_change}')

        if pct_change > 0:
            execution_log.append('Sub-branch NVDA-UP triggered')
            # Fetch RSI
            execution_log.append('Step 1b: Calling twelvedata_GetTimeSeriesRsi for NVDA')
            raw_rsi = call_tool('twelvedata_GetTimeSeriesRsi', {'symbol': 'NVDA', 'interval': '1day', 'time_period': 14, 'outputsize': 1})
            execution_log.append(f'[RAW] {str(raw_rsi)[:200]}')
            rsi_data = json.loads(raw_rsi) if isinstance(raw_rsi, str) else raw_rsi
            rsi_values = rsi_data.get('values', []) if isinstance(rsi_data, dict) else []
            rsi_val = None
            if rsi_values and len(rsi_values) > 0:
                rsi_val_str = rsi_values[0].get('rsi', None) if isinstance(rsi_values[0], dict) else None
                try:
                    rsi_val = float(rsi_val_str) if rsi_val_str is not None else None
                except (ValueError, TypeError):
                    rsi_val = None
            execution_log.append(f'NVDA RSI(14): {rsi_val}')

            # Fetch MACD
            execution_log.append('Step 1c: Calling twelvedata_GetTimeSeriesMacd for NVDA')
            raw_macd = call_tool('twelvedata_GetTimeSeriesMacd', {'symbol': 'NVDA', 'interval': '1day', 'outputsize': 1})
            execution_log.append(f'[RAW] {str(raw_macd)[:200]}')
            macd_data = json.loads(raw_macd) if isinstance(raw_macd, str) else raw_macd
            macd_values = macd_data.get('values', []) if isinstance(macd_data, dict) else []
            macd_hist_val = None
            if macd_values and len(macd_values) > 0:
                macd_hist_str = macd_values[0].get('macd_hist', None) if isinstance(macd_values[0], dict) else None
                try:
                    macd_hist_val = float(macd_hist_str) if macd_hist_str is not None else None
                except (ValueError, TypeError):
                    macd_hist_val = None
            execution_log.append(f'NVDA MACD hist: {macd_hist_val}')

            rsi_bullish = (rsi_val is not None and rsi_val > 60)
            macd_bullish = (macd_hist_val is not None and macd_hist_val > 0)
            if rsi_bullish and macd_bullish:
                nvda_signal = 'BULLISH-MOMENTUM'
            else:
                nvda_signal = 'BULLISH-WEAK'

        else:
            execution_log.append('Sub-branch NVDA-DOWN triggered')
            # Fetch BBands
            execution_log.append('Step 1b: Calling twelvedata_GetTimeSeriesBBands for NVDA')
            raw_bb = call_tool('twelvedata_GetTimeSeriesBBands', {'symbol': 'NVDA', 'interval': '1day', 'time_period': 20, 'outputsize': 1})
            execution_log.append(f'[RAW] {str(raw_bb)[:200]}')
            bb_data = json.loads(raw_bb) if isinstance(raw_bb, str) else raw_bb
            bb_values = bb_data.get('values', []) if isinstance(bb_data, dict) else []
            lower_band_val = None
            if bb_values and len(bb_values) > 0:
                lb_str = bb_values[0].get('lower_band', None) if isinstance(bb_values[0], dict) else None
                try:
                    lower_band_val = float(lb_str) if lb_str is not None else None
                except (ValueError, TypeError):
                    lower_band_val = None
            execution_log.append(f'NVDA BBands lower_band: {lower_band_val}')

            # Fetch ATR
            execution_log.append('Step 1c: Calling twelvedata_GetTimeSeriesAtr for NVDA')
            raw_atr = call_tool('twelvedata_GetTimeSeriesAtr', {'symbol': 'NVDA', 'interval': '1day', 'time_period': 14, 'outputsize': 1})
            execution_log.append(f'[RAW] {str(raw_atr)[:200]}')
            atr_data = json.loads(raw_atr) if isinstance(raw_atr, str) else raw_atr
            atr_values = atr_data.get('values', []) if isinstance(atr_data, dict) else []
            atr_val = None
            if atr_values and len(atr_values) > 0:
                atr_str = atr_values[0].get('atr', None) if isinstance(atr_values[0], dict) else None
                try:
                    atr_val = float(atr_str) if atr_str is not None else None
                except (ValueError, TypeError):
                    atr_val = None
            execution_log.append(f'NVDA ATR(14): {atr_val}')

            # Use current close from quote (already fetched) to compare vs lower_band
            try:
                close_price = float(quote_data.get('close', '0') or '0') if isinstance(quote_data, dict) else 0.0
            except (ValueError, TypeError):
                close_price = 0.0
            execution_log.append(f'NVDA close price: {close_price}')

            if lower_band_val is not None and close_price > 0 and close_price < lower_band_val:
                nvda_signal = 'BEARISH-VOLATILE'
            else:
                nvda_signal = 'BEARISH-STABLE'

    else:
        nvda_branch = 'MARKET-CLOSED'
        execution_log.append('Branch MARKET-CLOSED triggered')

        # Fetch EOD price
        execution_log.append('Step 1a: Calling twelvedata_GetEod for NVDA')
        raw_eod = call_tool('twelvedata_GetEod', {'symbol': 'NVDA'})
        execution_log.append(f'[RAW] {str(raw_eod)[:200]}')
        eod_data = json.loads(raw_eod) if isinstance(raw_eod, str) else raw_eod
        eod_close = None
        if isinstance(eod_data, dict):
            eod_close_str = eod_data.get('close', None)
            try:
                eod_close = float(eod_close_str) if eod_close_str is not None else None
            except (ValueError, TypeError):
                eod_close = None
        execution_log.append(f'NVDA EOD close: {eod_close}')

        # Fetch 50-period weekly SMA
        execution_log.append('Step 1b: Calling twelvedata_GetTimeSeriesSma for NVDA (weekly, 50-period)')
        raw_sma = call_tool('twelvedata_GetTimeSeriesSma', {'symbol': 'NVDA', 'interval': '1week', 'time_period': 50, 'outputsize': 1})
        execution_log.append(f'[RAW] {str(raw_sma)[:200]}')
        sma_data = json.loads(raw_sma) if isinstance(raw_sma, str) else raw_sma
        sma_values = sma_data.get('values', []) if isinstance(sma_data, dict) else []
        sma_val = None
        if sma_values and len(sma_values) > 0:
            sma_str = sma_values[0].get('sma', None) if isinstance(sma_values[0], dict) else None
            try:
                sma_val = float(sma_str) if sma_str is not None else None
            except (ValueError, TypeError):
                sma_val = None
        execution_log.append(f'NVDA Weekly SMA(50): {sma_val}')

        if eod_close is not None and sma_val is not None and eod_close > sma_val:
            nvda_signal = 'EOD-ABOVE-SMA50'
        else:
            nvda_signal = 'EOD-BELOW-SMA50'

    execution_log.append(f'NVDA signal determined: {nvda_signal} (branch: {nvda_branch})')

    # =========================================================
    # STEP 2: Crypto Price Gate
    # =========================================================
    execution_log.append('Step 2: Calling alchemy_fetchTokenPriceBySymbol for BTC and ETH')
    raw_crypto = call_tool('alchemy_fetchTokenPriceBySymbol', {'symbols': ['BTC', 'ETH']})
    execution_log.append(f'[RAW] {str(raw_crypto)[:200]}')
    crypto_data = json.loads(raw_crypto) if isinstance(raw_crypto, str) else raw_crypto

    # Extract BTC and ETH prices
    btc_price = None
    eth_price = None
    if isinstance(crypto_data, list):
        for item in crypto_data:
            if not isinstance(item, dict):
                continue
            sym = item.get('symbol', '') or ''
            price_str = item.get('price', None) or item.get('prices', [{}])
            # Try different possible response shapes
            if sym.upper() == 'BTC':
                if isinstance(price_str, (int, float)):
                    btc_price = float(price_str)
                elif isinstance(price_str, str):
                    try:
                        btc_price = float(price_str)
                    except (ValueError, TypeError):
                        pass
                elif isinstance(price_str, list) and len(price_str) > 0:
                    try:
                        btc_price = float(price_str[0].get('value', 0))
                    except (ValueError, TypeError, AttributeError):
                        pass
            elif sym.upper() == 'ETH':
                if isinstance(price_str, (int, float)):
                    eth_price = float(price_str)
                elif isinstance(price_str, str):
                    try:
                        eth_price = float(price_str)
                    except (ValueError, TypeError):
                        pass
                elif isinstance(price_str, list) and len(price_str) > 0:
                    try:
                        eth_price = float(price_str[0].get('value', 0))
                    except (ValueError, TypeError, AttributeError):
                        pass
    elif isinstance(crypto_data, dict):
        # Alternative: dict keyed by symbol
        btc_entry = crypto_data.get('BTC', crypto_data.get('btc', {}))
        eth_entry = crypto_data.get('ETH', crypto_data.get('eth', {}))
        if isinstance(btc_entry, dict):
            try:
                btc_price = float(btc_entry.get('price', 0) or 0)
            except (ValueError, TypeError):
                btc_price = None
        if isinstance(eth_entry, dict):
            try:
                eth_price = float(eth_entry.get('price', 0) or 0)
            except (ValueError, TypeError):
                eth_price = None

    execution_log.append(f'BTC price (USD): {btc_price}')
    execution_log.append(f'ETH price (USD): {eth_price}')

    btc_branch = None
    btc_metric_key = None
    btc_metric_val = None
    btc_crash_mode = False

    if btc_price is not None and btc_price > 60000:
        btc_branch = 'BTC-HIGH'
        execution_log.append('BTC Branch BTC-HIGH triggered (price > 60000)')
        execution_log.append('Step 2a: Calling alchemy_fetchTokenPriceHistoryBySymbol for BTC')
        raw_btc_hist = call_tool('alchemy_fetchTokenPriceHistoryBySymbol', {'symbol': 'BTC', 'startTime': '2024-01-01', 'endTime': '2024-01-08', 'interval': '1h'})
        execution_log.append(f'[RAW] {str(raw_btc_hist)[:200]}')
        btc_hist_data = json.loads(raw_btc_hist) if isinstance(raw_btc_hist, str) else raw_btc_hist
        # Extract history prices and find peak
        hist_prices = []
        if isinstance(btc_hist_data, list):
            for pt in btc_hist_data:
                if isinstance(pt, dict):
                    try:
                        hist_prices.append(float(pt.get('price', pt.get('value', pt.get('close', 0))) or 0))
                    except (ValueError, TypeError):
                        pass
        elif isinstance(btc_hist_data, dict):
            data_arr = btc_hist_data.get('data', btc_hist_data.get('prices', btc_hist_data.get('values', [])))
            if isinstance(data_arr, list):
                for pt in data_arr:
                    if isinstance(pt, dict):
                        try:
                            hist_prices.append(float(pt.get('price', pt.get('value', pt.get('close', 0))) or 0))
                        except (ValueError, TypeError):
                            pass
        btc_peak = max(hist_prices) if hist_prices else None
        btc_metric_key = 'btc_peak'
        btc_metric_val = btc_peak
        execution_log.append(f'btc_peak: {btc_peak}')

    elif btc_price is not None and btc_price > 30000:
        btc_branch = 'BTC-MID'
        execution_log.append('BTC Branch BTC-MID triggered (30000 < price <= 60000)')
        execution_log.append('Step 2a: Calling twelvedata_GetTimeSeries for BTC/USD (daily, 7 bars)')
        raw_btc_ts = call_tool('twelvedata_GetTimeSeries', {'symbol': 'BTC/USD', 'interval': '1day', 'outputsize': 7})
        execution_log.append(f'[RAW] {str(raw_btc_ts)[:200]}')
        btc_ts_data = json.loads(raw_btc_ts) if isinstance(raw_btc_ts, str) else raw_btc_ts
        ts_values = btc_ts_data.get('values', []) if isinstance(btc_ts_data, dict) else []
        close_prices = []
        for bar in ts_values:
            if isinstance(bar, dict):
                c_str = bar.get('close', None)
                try:
                    close_prices.append(float(c_str))
                except (ValueError, TypeError):
                    pass
        btc_7d_avg = round(sum(close_prices) / len(close_prices), 2) if close_prices else None
        btc_metric_key = 'btc_7d_avg'
        btc_metric_val = btc_7d_avg
        execution_log.append(f'btc_7d_avg: {btc_7d_avg}')

    else:
        btc_branch = 'BTC-LOW'
        btc_crash_mode = True
        execution_log.append('BTC Branch BTC-LOW triggered (price <= 30000)')
        execution_log.append('Step 2a: Calling twelvedata_GetExchangeRate for ETH/USD')
        raw_eth_rate = call_tool('twelvedata_GetExchangeRate', {'symbol': 'ETH/USD'})
        execution_log.append(f'[RAW] {str(raw_eth_rate)[:200]}')
        eth_rate_data = json.loads(raw_eth_rate) if isinstance(raw_eth_rate, str) else raw_eth_rate
        eth_usd_rate = eth_rate_data.get('rate', None) if isinstance(eth_rate_data, dict) else None
        btc_metric_key = 'eth_usd_rate'
        btc_metric_val = eth_usd_rate
        execution_log.append(f'eth_usd_rate: {eth_usd_rate}')

    # ETH sub-check: if ETH price > 2000, fetch WETH on-chain price
    weth_parity = 'N/A'
    if eth_price is not None and eth_price > 2000:
        execution_log.append('ETH price > 2000: Calling alchemy_fetchTokenPriceByAddress for WETH')
