                latest_macd_signal_val = None
            try:
                latest_macd_hist_val = float(latest_macd_hist_str) if latest_macd_hist_str is not None else None
            except (ValueError, TypeError):
                latest_macd_hist_val = None
        execution_log.append(f"Latest MACD: {latest_macd_val}, Signal: {latest_macd_signal_val}, Hist: {latest_macd_hist_val}")

        branch_result = {
            'branch': 'A',
            'reason': f'BULLISH day: percent_change={percent_change:.4f}% > 0',
            'rsi_14': latest_rsi_val,
            'rsi_zone': rsi_zone,
            'macd': latest_macd_val,
            'macd_signal': latest_macd_signal_val,
            'macd_hist': latest_macd_hist_val
        }

    elif percent_change < 0:
        execution_log.append(f"Branch B triggered: BEARISH day (percent_change={percent_change:.4f} < 0)")

        # Fetch Bollinger Bands
        execution_log.append("Step 2B-1: Fetching Bollinger Bands for NVDA (daily, 5 points)")
        raw_bb = call_tool('twelvedata_GetTimeSeriesBBands', {'params': {'symbol': 'NVDA', 'interval': '1day', 'time_period': 20, 'outputsize': 5}})
        execution_log.append(f"[RAW] {str(raw_bb)[:300]}")
        bb_data = json.loads(raw_bb) if isinstance(raw_bb, str) else raw_bb
        bb_values = bb_data.get('values', [])
        if bb_values is None:
            bb_values = []
        upper_band = None
        middle_band = None
        lower_band = None
        if len(bb_values) > 0:
            try:
                upper_band = float(bb_values[0].get('upper_band', None)) if bb_values[0].get('upper_band') is not None else None
            except (ValueError, TypeError):
                upper_band = None
            try:
                middle_band = float(bb_values[0].get('middle_band', None)) if bb_values[0].get('middle_band') is not None else None
            except (ValueError, TypeError):
                middle_band = None
            try:
                lower_band = float(bb_values[0].get('lower_band', None)) if bb_values[0].get('lower_band') is not None else None
            except (ValueError, TypeError):
                lower_band = None
        execution_log.append(f"BB Upper: {upper_band}, Middle: {middle_band}, Lower: {lower_band}")

        # Determine band position
        if close_price is not None and upper_band is not None and lower_band is not None:
            if close_price > upper_band:
                band_position = 'ABOVE UPPER BAND (overbought zone)'
            elif close_price < lower_band:
                band_position = 'BELOW LOWER BAND (oversold zone)'
            else:
                band_position = 'BETWEEN BANDS (neutral zone)'
        else:
            band_position = 'UNKNOWN'
        execution_log.append(f"Price {close_price} vs Bands -> {band_position}")

        # Fetch ATR
        execution_log.append("Step 2B-2: Fetching 14-period ATR for NVDA (daily, 5 points)")
        raw_atr = call_tool('twelvedata_GetTimeSeriesAtr', {'params': {'symbol': 'NVDA', 'interval': '1day', 'time_period': 14, 'outputsize': 5}})
        execution_log.append(f"[RAW] {str(raw_atr)[:300]}")
        atr_data = json.loads(raw_atr) if isinstance(raw_atr, str) else raw_atr
        atr_values = atr_data.get('values', [])
        if atr_values is None:
            atr_values = []
        latest_atr_val = None
        if len(atr_values) > 0:
            try:
                latest_atr_val = float(atr_values[0].get('atr', None)) if atr_values[0].get('atr') is not None else None
            except (ValueError, TypeError):
                latest_atr_val = None
        execution_log.append(f"Latest ATR (14): {latest_atr_val}")

        branch_result = {
            'branch': 'B',
            'reason': f'BEARISH day: percent_change={percent_change:.4f}% < 0',
            'upper_band': upper_band,
            'middle_band': middle_band,
            'lower_band': lower_band,
            'band_position': band_position,
            'atr_14': latest_atr_val
        }

    else:
        execution_log.append(f"Branch C triggered: FLAT day (percent_change={percent_change} == 0)")

        # Fetch SMA 50
        execution_log.append("Step 2C: Fetching 50-period SMA for NVDA (daily, 5 points)")
        raw_sma = call_tool('twelvedata_GetTimeSeriesSma', {'params': {'symbol': 'NVDA', 'interval': '1day', 'time_period': 50, 'outputsize': 5}})
        execution_log.append(f"[RAW] {str(raw_sma)[:300]}")
        sma_data = json.loads(raw_sma) if isinstance(raw_sma, str) else raw_sma
        sma_values = sma_data.get('values', [])
        if sma_values is None:
            sma_values = []
        latest_sma_val = None
        if len(sma_values) > 0:
            try:
                latest_sma_val = float(sma_values[0].get('sma', None)) if sma_values[0].get('sma') is not None else None
            except (ValueError, TypeError):
                latest_sma_val = None
        execution_log.append(f"Latest SMA (50): {latest_sma_val}")

        sma_position = 'UNKNOWN'
        if close_price is not None and latest_sma_val is not None:
            if close_price > latest_sma_val:
                sma_position = 'ABOVE SMA (bullish)'
            else:
                sma_position = 'BELOW SMA (bearish)'
        execution_log.append(f"Price {close_price} vs SMA -> {sma_position}")

        branch_result = {
            'branch': 'C',
            'reason': 'FLAT day: percent_change == 0',
            'sma_50': latest_sma_val,
            'sma_position': sma_position
        }

    # Step 3: 52-week range analysis (always runs)
    execution_log.append("Step 3: Computing 52-week range analysis")
    fw_distance_pct = None
    if close_price is not None and fw_high is not None and fw_high != 0:
        fw_distance_pct = (close_price - fw_high) / fw_high * 100
    execution_log.append(f"52w High: {fw_high}, 52w Low: {fw_low}, Current: {close_price}")
    execution_log.append(f"Distance from 52w high: {fw_distance_pct:.2f}%" if fw_distance_pct is not None else "Distance from 52w high: N/A")

    # Final signal summary
    signal = 'NEUTRAL'
    if branch_result.get('branch') == 'A':
        rsi_v = branch_result.get('rsi_14')
        macd_v = branch_result.get('macd')
        macd_sig = branch_result.get('macd_signal')
        if rsi_v is not None and macd_v is not None and macd_sig is not None:
            if rsi_v < 70 and macd_v > macd_sig:
                signal = 'BULLISH'
            elif rsi_v > 70:
                signal = 'NEUTRAL (overbought caution)'
            else:
                signal = 'NEUTRAL'
        else:
            signal = 'BULLISH (up day, insufficient indicator data)'
    elif branch_result.get('branch') == 'B':
        band_pos = branch_result.get('band_position', '')
        if 'oversold' in band_pos.lower():
            signal = 'NEUTRAL (potential reversal, oversold)'
        elif 'overbought' in band_pos.lower():
            signal = 'BEARISH (overextended)'
        else:
            signal = 'BEARISH'
    elif branch_result.get('branch') == 'C':
        sma_pos = branch_result.get('sma_position', '')
        if 'above' in sma_pos.lower():
            signal = 'NEUTRAL-BULLISH'
        else:
            signal = 'NEUTRAL-BEARISH'

    execution_log.append(f"Overall signal: {signal}")

    # Compile final report
    final_report = {
        'nvda_quote_summary': {
            'close': close_price,
            'percent_change': percent_change,
            '52w_high': fw_high,
            '52w_low': fw_low,
            'distance_from_52w_high_pct': round(fw_distance_pct, 2) if fw_distance_pct is not None else None
        },
        'branch_triggered': branch_result,
        'overall_signal': signal
    }
    execution_log.append(f"FINAL REPORT: {json.dumps(final_report, indent=2)}")

    return '\n'.join(execution_log)

